def joint_angle(
    a: Keypoint | None, b: Keypoint | None, c: Keypoint | None
) -> float | None:
    """Angle at point b formed by vectors b->a and b->c, in degrees."""
    if any(kp is None for kp in (a, b, c)):
        return None

    vector_ba = (a["x"] - b["x"], a["y"] - b["y"])
    vector_bc = (c["x"] - b["x"], c["y"] - b["y"])

    dot_product = vector_ba[0] * vector_bc[0] + vector_ba[1] * vector_bc[1]
    magnitude_ba = math.hypot(vector_ba[0], vector_ba[1])
    magnitude_bc = math.hypot(vector_bc[0], vector_bc[1])

    if magnitude_ba < 1e-6 or magnitude_bc < 1e-6:
        return None

    cosine = dot_product / (magnitude_ba * magnitude_bc)
    cosine = max(-1.0, min(1.0, cosine))

    return math.degrees(math.acos(cosine))

