def topo_sort(spec: GraphSpec) -> list[str]:
    """Return node IDs in topological execution order."""
    nodes = {n["id"]: n for n in spec.get("nodes", [])}
    sorter = TopologicalSorter()

    # Add all nodes to the sorter
    for node_id in nodes:
        sorter.add(node_id)

    # Add edges to establish dependencies
    # An edge from node A to node B means A must execute before B
    for edge in spec.get("edges", []):
        from_node = edge.get("from_node")
        to_node = edge.get("to_node")
        if from_node and to_node:
            sorter.add(to_node, from_node)

    # Perform topological sort; raises CycleError if a cycle exists
    return list(sorter.static_order())

