def topo_sort(spec: GraphSpec) -> list[str]:
    """Return node IDs in topological execution order."""
    nodes = {n["id"] for n in spec.get("nodes", [])}
    edges = spec.get("edges", [])

    deps: dict[str, set[str]] = {n: set() for n in nodes}

    for edge in edges:
        fn = edge.get("from_node")
        tn = edge.get("to_node")
        if fn not in nodes:
            raise KeyError(f"Edge references unknown source node: {fn!r}")
        if tn not in nodes:
            raise KeyError(f"Edge references unknown target node: {tn!r}")
        deps[tn].add(fn)

    sorter = TopologicalSorter(deps)
    return list(sorter.static_order())

