def validate(spec: GraphSpec) -> list[str]:
    """Return a list of validation errors. Empty list means the graph is valid."""
    issues: list[str] = []
    node_map = {n["id"]: n for n in spec.get("nodes", [])}

    # Check node types are registered
    for node in spec.get("nodes", []):
        node_type = node.get("type", "")
        try:
            registry.get(node_type)
        except KeyError as e:
            issues.append(str(e))

    # Check edges
    for edge in spec.get("edges", []):
        required_fields = ("from_node", "from_port", "to_node", "to_port")
        missing = [f for f in required_fields if not edge.get(f)]
        if missing:
            for field in missing:
                issues.append(f"Edge missing field {field!r}: {edge}")
            continue

        from_node_id = edge["from_node"]
        to_node_id = edge["to_node"]

        # Validate node references
        if from_node_id not in node_map:
            issues.append(f"Edge references unknown source node: {from_node_id!r}")
        if to_node_id not in node_map:
            issues.append(f"Edge references unknown target node: {to_node_id!r}")

        # Check port type compatibility
        if from_node_id in node_map and to_node_id in node_map:
            from_type = node_map[from_node_id].get("type", "")
            to_type = node_map[to_node_id].get("type", "")
            try:
                from_inst = registry.get(from_type)()
                to_inst = registry.get(to_type)()
                from_port = edge["from_port"]
                to_port = edge["to_port"]
                out_type = from_inst.output_ports.get(from_port)
                in_type = to_inst.input_ports.get(to_port)
                if out_type and in_type:
                    allowed_types = {t.strip() for t in in_type.split("|")}
                    if out_type not in allowed_types:
                        issues.append(
                            f"Type mismatch: {from_node_id}.{from_port} ({out_type}) -> {to_node_id}.{to_port} ({in_type})"
                        )
            except KeyError:
                pass

    # Check for cycles
    try:
        topo_sort(spec)
    except CycleError as e:
        issues.append(f"Graph contains a cycle: {e}")

    return issues

